using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Breaking change: EF Core 9 renamed the discriminator property
            // from "Discriminator" to "$type". Preserve the old name so existing
            // 500K documents and direct SQL queries (c.Discriminator) keep working.
            entity.HasDiscriminator<string>("Discriminator").HasValue("Product");

            // Breaking change: EF Core 9 changed the id format from
            // "Product|123" to just "123". Preserve the old format so existing
            // documents remain readable.
            entity.Property(p => p.Id).ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });

        // Breaking change: HasIndex() now throws for Cosmos DB because indexes
        // are managed server-side. Removed the HasIndex(p => p.Sku) call.
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Breaking change: EF Core 9 removed sync APIs for Cosmos DB.
        // Callers must use async (ToListAsync, SaveChangesAsync, etc.).
        // See CosmosQuery.cs for updated call sites.
    }
}

